sys_variable_value.value:
(function execute(inputs, outputs) {
    var userGr = new GlideRecord("sys_user");
        
    var userName;
    if (userGr.get("sys_id", inputs.reserved_for)) {
        userName = userGr.getValue("name");        
    }

    var workspaceGr = new GlideRecord("x_1759267_wrm_workspace_options");
        
    var workspaceName;
    if (workspaceGr.get("sys_id", inputs.workspace)) {
        workspaceName = workspaceGr.getValue("workspace_name");        
    }

    var trackerLink = ''; 
    if (inputs.tracker_record) { 
        var instanceURL = gs.getProperty('glide.servlet.uri'); 
        var tableName = inputs.tracker_record.getRecordClassName(); 
        var sysId = inputs.tracker_record.getUniqueValue(); 
        
        trackerLink = instanceURL + tableName + '.do?sys_id=' + sysId; 
    }

    if (userName && workspaceName) {
        var action = inputs.action;
        var message = action.toUpperCase() + " reservation for:\n\nName: " + userName +
                      "\n\nWorkspace: " + workspaceName +
                      "\n\nStart Date/Time: " + inputs.start_date_time;

        if (trackerLink) {
            message +=  '\n\n🔗 View Tracker Record: ' + trackerLink;
            message += '\n📋 Please claim this reservation to begin preparation.';
        }

        new discordNotification().sendMessage(message, inputs.action == "approved" ? '✅' : '❌');
    } else {
        gs.error("Script Step | Error: Unable to get user or workspace name");
    }
})(inputs, outputs);

